import 'package:flutter/foundation.dart';

enum ViewerExportPhase { idle, sheetOpen, exporting }

/// Normalizes export progress telemetry for determinate UI rendering.
///
/// Export backends may report malformed progress while falling back between
/// codecs or platform capture paths. Keep invalid samples indeterminate instead
/// of letting [double.clamp] turn NaN into a determinate edge value.
class ViewerExportProgress {
  const ViewerExportProgress._();

  static double? normalize(double progress) {
    if (!progress.isFinite) return null;
    return progress.clamp(0.0, 1.0).toDouble();
  }
}

@immutable
class ViewerExportAutoExplorePlayback {
  final bool isExploring;
  final bool isPaused;
  final bool pausedByUserCorrection;

  const ViewerExportAutoExplorePlayback({
    required this.isExploring,
    required this.isPaused,
    required this.pausedByUserCorrection,
  }) : assert(
          !pausedByUserCorrection || (isExploring && !isPaused),
          'pausedByUserCorrection is only valid while auto-explore is armed',
        );

  bool get isArmedButTemporarilyYielded =>
      isExploring && !isPaused && pausedByUserCorrection;
}

/// Pure pause/resume plan for export flows that temporarily suspend auto-explore.
///
/// Keeping this decision outside the viewer mixin makes the hidden replay order
/// visible: the export flow should resume auto-explore only when it paused
/// active auto-motion itself.
@immutable
class ViewerExportAutoExplorePausePlan {
  final bool pauseService;
  final bool resumeWhenFinished;

  const ViewerExportAutoExplorePausePlan({
    required this.pauseService,
    required this.resumeWhenFinished,
  });

  factory ViewerExportAutoExplorePausePlan.fromPlayback(
    ViewerExportAutoExplorePlayback playback,
  ) {
    final ownsAutoMotion = playback.isExploring &&
        !playback.isPaused &&
        !playback.pausedByUserCorrection;
    return ViewerExportAutoExplorePausePlan(
      pauseService: ownsAutoMotion,
      resumeWhenFinished: ownsAutoMotion,
    );
  }
}

@immutable
class ViewerExportSession {
  final ViewerExportPhase phase;
  final bool resumeAutoExploreWhenFinished;
  final double? progress;

  const ViewerExportSession({
    this.phase = ViewerExportPhase.idle,
    this.resumeAutoExploreWhenFinished = false,
    this.progress,
  });

  bool get freezeFrame => phase != ViewerExportPhase.idle;
  bool get isExporting => phase == ViewerExportPhase.exporting;
  bool get isSheetOpen => phase == ViewerExportPhase.sheetOpen;

  ViewerExportSession openSheet({
    required bool resumeAutoExploreWhenFinished,
  }) {
    return ViewerExportSession(
      phase: ViewerExportPhase.sheetOpen,
      resumeAutoExploreWhenFinished: resumeAutoExploreWhenFinished,
    );
  }

  ViewerExportSession dismissSheet() {
    if (!isSheetOpen) return this;
    return const ViewerExportSession();
  }

  ViewerExportSession startExport() {
    if (isExporting) return this;
    return ViewerExportSession(
      phase: ViewerExportPhase.exporting,
      resumeAutoExploreWhenFinished: resumeAutoExploreWhenFinished,
      progress: 0,
    );
  }

  ViewerExportSession updateProgress(double nextProgress) {
    if (!isExporting) return this;
    return ViewerExportSession(
      phase: phase,
      resumeAutoExploreWhenFinished: resumeAutoExploreWhenFinished,
      progress: ViewerExportProgress.normalize(nextProgress),
    );
  }

  ViewerExportSession finish() => const ViewerExportSession();
}

import 'package:flutter_fractals/features/viewer/export/viewer_export_session.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('ViewerExportAutoExplorePausePlan', () {
    test('does not resume auto-explore that was already yielded to the user',
        () {
      const playback = ViewerExportAutoExplorePlayback(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: true,
      );

      final plan = ViewerExportAutoExplorePausePlan.fromPlayback(playback);

      expect(playback.isArmedButTemporarilyYielded, isTrue);
      expect(plan.pauseService, isFalse);
      expect(plan.resumeWhenFinished, isFalse);
    });

    test('pauses and resumes only active auto-motion', () {
      final activePlan = ViewerExportAutoExplorePausePlan.fromPlayback(
        const ViewerExportAutoExplorePlayback(
          isExploring: true,
          isPaused: false,
          pausedByUserCorrection: false,
        ),
      );
      final pausedPlan = ViewerExportAutoExplorePausePlan.fromPlayback(
        const ViewerExportAutoExplorePlayback(
          isExploring: true,
          isPaused: true,
          pausedByUserCorrection: false,
        ),
      );
      final idlePlan = ViewerExportAutoExplorePausePlan.fromPlayback(
        const ViewerExportAutoExplorePlayback(
          isExploring: false,
          isPaused: false,
          pausedByUserCorrection: false,
        ),
      );

      expect(activePlan.pauseService, isTrue);
      expect(activePlan.resumeWhenFinished, isTrue);
      expect(pausedPlan.pauseService, isFalse);
      expect(pausedPlan.resumeWhenFinished, isFalse);
      expect(idlePlan.pauseService, isFalse);
      expect(idlePlan.resumeWhenFinished, isFalse);
    });
  });

  group('ViewerExportSession', () {
    test('freezes while sheet is open and resumes to idle when dismissed', () {
      final session = const ViewerExportSession().openSheet(
        resumeAutoExploreWhenFinished: true,
      );

      expect(session.phase, ViewerExportPhase.sheetOpen);
      expect(session.freezeFrame, isTrue);
      expect(session.isExporting, isFalse);
      expect(session.resumeAutoExploreWhenFinished, isTrue);

      final dismissed = session.dismissSheet();
      expect(dismissed.phase, ViewerExportPhase.idle);
      expect(dismissed.freezeFrame, isFalse);
      expect(dismissed.resumeAutoExploreWhenFinished, isFalse);
    });

    test('stays exporting when sheet dismisses after export has started', () {
      final exporting = const ViewerExportSession()
          .openSheet(resumeAutoExploreWhenFinished: true)
          .startExport()
          .updateProgress(0.5);

      final afterDismiss = exporting.dismissSheet();
      expect(afterDismiss.phase, ViewerExportPhase.exporting);
      expect(afterDismiss.freezeFrame, isTrue);
      expect(afterDismiss.isExporting, isTrue);
      expect(afterDismiss.progress, 0.5);
      expect(afterDismiss.resumeAutoExploreWhenFinished, isTrue);
    });

    test('finish resets the session back to idle', () {
      final finished = const ViewerExportSession()
          .openSheet(resumeAutoExploreWhenFinished: true)
          .startExport()
          .finish();

      expect(finished.phase, ViewerExportPhase.idle);
      expect(finished.freezeFrame, isFalse);
      expect(finished.isExporting, isFalse);
      expect(finished.progress, isNull);
      expect(finished.resumeAutoExploreWhenFinished, isFalse);
    });

    test('progress is clamped to a valid export range', () {
      final exporting = const ViewerExportSession()
          .openSheet(resumeAutoExploreWhenFinished: true)
          .startExport();

      expect(exporting.updateProgress(-1).progress, 0);
      expect(exporting.updateProgress(2).progress, 1);
    });

    test('non-finite progress falls back to indeterminate progress', () {
      final exporting = const ViewerExportSession()
          .openSheet(resumeAutoExploreWhenFinished: true)
          .startExport();

      for (final sample in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        expect(
          exporting.updateProgress(sample).progress,
          isNull,
          reason: 'sample=$sample',
        );
      }
    });

    test('startExport is a no-op once export is already active', () {
      final exporting = const ViewerExportSession()
          .openSheet(resumeAutoExploreWhenFinished: true)
          .startExport()
          .updateProgress(0.4);

      final restarted = exporting.startExport();

      expect(restarted.phase, ViewerExportPhase.exporting);
      expect(restarted.progress, 0.4);
      expect(restarted.resumeAutoExploreWhenFinished, isTrue);
    });
  });
}

import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Parsed deep link data containing fractal configuration.
///
/// This class represents the configuration extracted from a deep link URL
/// like `fractalforge://view?type=mandelbrot&zoom=10&x=0.5`.
///
/// {@category Services}
class DeepLinkData {
  /// The fractal module ID (e.g., 'mandelbrot', 'julia', 'mandelbulb').
  final String type;

  /// Zoom level (magnification).
  final double? zoom;

  /// Pan X coordinate (2D fractals).
  final double? x;

  /// Pan Y coordinate (2D fractals).
  final double? y;

  /// Rotation X angle in radians (3D fractals).
  final double? rotX;

  /// Rotation Y angle in radians (3D fractals).
  final double? rotY;

  /// Rotation Z angle in radians (3D fractals).
  final double? rotZ;

  /// Number of iterations.
  final int? iterations;

  /// Bailout radius.
  final double? bailout;

  /// Color scheme index.
  final int? colorScheme;

  /// Power parameter (for fractals like Mandelbulb).
  final double? power;

  /// Julia set real constant (c.x) from the public `juliaX` URL alias.
  final double? juliaX;

  /// Julia set imaginary constant (c.y) from the public `juliaY` URL alias.
  final double? juliaY;

  const DeepLinkData({
    required this.type,
    this.zoom,
    this.x,
    this.y,
    this.rotX,
    this.rotY,
    this.rotZ,
    this.iterations,
    this.bailout,
    this.colorScheme,
    this.power,
    this.juliaX,
    this.juliaY,
  });

  /// Creates a [FractalViewState] from the parsed deep link data.
  FractalViewState toViewState() {
    return FractalViewState(
      pan: Vector2(x ?? 0.0, y ?? 0.0),
      zoom: zoom ?? 1.0,
      rotation: Vector3(rotX ?? 0.0, rotY ?? 0.0, rotZ ?? 0.0),
    );
  }

  /// Extracts fractal parameters from the deep link data.
  ///
  /// Returns a map of parameter IDs to values.
  Map<String, Object> toParams() {
    final params = <String, Object>{};

    if (iterations != null) params['iterations'] = iterations!;
    if (bailout != null) params['bailout'] = bailout!;
    if (colorScheme != null) params['colorScheme'] = colorScheme!;
    if (power != null) params['power'] = power!;
    _DeepLinkJuliaConstantParams.addRuntimeParams(
      params,
      real: juliaX,
      imaginary: juliaY,
    );

    return params;
  }

  @override
  String toString() {
    return 'DeepLinkData(type: $type, zoom: $zoom, x: $x, y: $y, '
        'rotX: $rotX, rotY: $rotY, rotZ: $rotZ, iterations: $iterations, '
        'bailout: $bailout, colorScheme: $colorScheme, power: $power, '
        'juliaX: $juliaX, juliaY: $juliaY)';
  }
}

/// Service for handling deep links with the `fractalforge://` scheme.
///
/// Supports URLs like:
/// - `fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1`
/// - `fractalforge://view?type=julia&juliaX=-0.7&juliaY=0.27&colorScheme=2`
/// - `fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&power=8`
///
/// {@category Services}
enum _DeepLinkRouteKind {
  customSchemeView,
  universalLinkView,
  rejected,
}

/// Shared view-route path contract for custom-scheme and universal links.
class _DeepLinkViewRoutePath {
  static const String pathOnlyView = DeepLinkService.host;
  static const String absoluteView = '/${DeepLinkService.host}';

  const _DeepLinkViewRoutePath._();

  /// A URI path that addresses the view route itself, with or without the
  /// canonical trailing slash some universal-link providers append.
  static bool isAbsoluteViewPath(String path) {
    return path == absoluteView || path == '$absoluteView/';
  }

  static bool isAuthorityRoot(String path) {
    return path.isEmpty || path == '/';
  }

  static bool isPathOnlyCustomSchemeView(String path) {
    return path == pathOnlyView || isAbsoluteViewPath(path);
  }
}

/// Normalized custom-scheme route shape.
///
/// `fractalforge://view?...` uses `view` as URI authority/host, while
/// `fractalforge:/view?...` and `fractalforge:view?...` are path-only forms.
/// Keep those shapes distinct so a non-view authority cannot smuggle a view
/// route through its path (for example `fractalforge://other/view?...`).
class _DeepLinkCustomRouteShape {
  final String host;
  final String path;

  const _DeepLinkCustomRouteShape({
    required this.host,
    required this.path,
  });

  factory _DeepLinkCustomRouteShape.fromUri(Uri uri) {
    return _DeepLinkCustomRouteShape(host: uri.host, path: uri.path);
  }

  bool get hasAuthority => host.isNotEmpty;

  bool get isViewRoute {
    if (hasAuthority) {
      return host == DeepLinkService.host &&
          _DeepLinkViewRoutePath.isAuthorityRoot(path);
    }
    return _DeepLinkViewRoutePath.isPathOnlyCustomSchemeView(path);
  }
}

class _DeepLinkRoute {
  static const allowedWebHosts = {'fractalforge.app', 'www.fractalforge.app'};

  final _DeepLinkRouteKind kind;

  const _DeepLinkRoute._(this.kind);

  bool get isAccepted => kind != _DeepLinkRouteKind.rejected;

  factory _DeepLinkRoute.fromUri(Uri uri) {
    if (uri.scheme == DeepLinkService.scheme) {
      return _DeepLinkRoute._(
        _isCustomViewRoute(uri)
            ? _DeepLinkRouteKind.customSchemeView
            : _DeepLinkRouteKind.rejected,
      );
    }

    if (uri.scheme == 'https' && allowedWebHosts.contains(uri.host)) {
      return _DeepLinkRoute._(
        _isWebViewRoute(uri)
            ? _DeepLinkRouteKind.universalLinkView
            : _DeepLinkRouteKind.rejected,
      );
    }

    return const _DeepLinkRoute._(_DeepLinkRouteKind.rejected);
  }

  static bool _isCustomViewRoute(Uri uri) {
    return _DeepLinkCustomRouteShape.fromUri(uri).isViewRoute;
  }

  static bool _isWebViewRoute(Uri uri) {
    return _DeepLinkViewRoutePath.isAbsoluteViewPath(uri.path);
  }
}

class _DeepLinkModuleId {
  static final RegExp _safePattern = RegExp(r'^[a-z0-9_]+$');

  const _DeepLinkModuleId._();

  static bool isSafe(String moduleId) => _safePattern.hasMatch(moduleId);

  static String requireSafeForBuild(String moduleId) {
    if (!isSafe(moduleId)) {
      throw ArgumentError.value(
        moduleId,
        'moduleId',
        'Deep-link module IDs must match ${_safePattern.pattern}',
      );
    }
    return moduleId;
  }
}

class _DeepLinkQuery {
  static final recognizedNames = {
    'type',
    for (final param in DeepLinkService._allQueryParams) param.name,
  };

  final Map<String, String> _params;

  const _DeepLinkQuery._(this._params);

  factory _DeepLinkQuery.fromUri(Uri uri) {
    final duplicatedRecognizedKeys = uri.queryParametersAll.entries.where(
      (entry) => recognizedNames.contains(entry.key) && entry.value.length > 1,
    );
